import{_ as e,z as t,m as a,ap as r}from"./chunks/framework.bQJNM8pB.js";const i="/adapter-yunhupro/assets/058e81af-eabf-44a8-9227-f023afd69711.CK9GXaiH.png",l="/adapter-yunhupro/assets/dee633e3-6d9b-4e5d-9438-a8c2c8501647.DnajvuuY.png",s="/adapter-yunhupro/assets/screenshot_2026-04-25_21-03-50.kGPFCRRH.png",n="/adapter-yunhupro/assets/screenshot_2026-04-25_21-06-28.DXkemhGo.png",h="/adapter-yunhupro/assets/2025-10-24_15-43-37.COPgmC4w.png",d="/adapter-yunhupro/assets/495cb157-5c28-4837-b736-40982172dd44.CTN8oxdI.png",q=JSON.parse('{"title":"首次接入指南","description":"","frontmatter":{},"headers":[],"relativePath":"markdown/firstime/start.md","filePath":"markdown/firstime/start.md","lastUpdated":1777129761000}'),c={name:"markdown/firstime/start.md"};function p(b,o,u,k,g,m){return a(),t("div",null,[...o[0]||(o[0]=[r('<h1 id="首次接入指南" tabindex="-1">首次接入指南 <a class="header-anchor" href="#首次接入指南" aria-label="Permalink to &quot;首次接入指南&quot;">​</a></h1><h2 id="首次接入和配置" tabindex="-1">首次接入和配置 <a class="header-anchor" href="#首次接入和配置" aria-label="Permalink to &quot;首次接入和配置&quot;">​</a></h2><p>本指南将引导您完成 <code>adapter-yunhupro</code> 在 Koishi 中的首次接入和配置。</p><h2 id="_1-前置要求" tabindex="-1">1. 前置要求 <a class="header-anchor" href="#_1-前置要求" aria-label="Permalink to &quot;1. 前置要求&quot;">​</a></h2><p>云湖平台支持两种连接方式：</p><h3 id="websocket-方式-推荐" tabindex="-1">WebSocket 方式（推荐） <a class="header-anchor" href="#websocket-方式-推荐" aria-label="Permalink to &quot;WebSocket 方式（推荐）&quot;">​</a></h3><p><strong>无需公网 IP</strong>，通过 WebSocket 长连接接收事件推送。</p><p>这是默认且推荐的连接方式，配置简单，无需额外的网络配置。</p><h3 id="webhook-方式" tabindex="-1">Webhook 方式 <a class="header-anchor" href="#webhook-方式" aria-label="Permalink to &quot;Webhook 方式&quot;">​</a></h3><p>通过 Webhook 接收事件推送，<strong>需要公网访问能力</strong>。</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>如果选择 Webhook 方式，您需要具备<strong>以下条件之一</strong>：</p><ul><li>拥有一个公网 IPv4 或 IPv6 地址。</li><li>使用内网穿透服务（如 frp, Ngrok, Cloudflare Tunnel 等）将您的本地 Koishi 服务暴露到公网。</li></ul></div><h2 id="连接方式对比" tabindex="-1">连接方式对比 <a class="header-anchor" href="#连接方式对比" aria-label="Permalink to &quot;连接方式对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>特性</th><th>WebSocket</th><th>Webhook</th></tr></thead><tbody><tr><td>公网 IP</td><td>不需要</td><td>需要</td></tr><tr><td>配置难度</td><td>⭐ 简单</td><td>⭐⭐⭐ 复杂</td></tr><tr><td>多机器人</td><td>✅ 无限制</td><td>⚠️ 需要不同路径</td></tr><tr><td>消息混乱</td><td>❌ 不会</td><td>⚠️ 路径相同时会</td></tr><tr><td>推荐程度</td><td>⭐⭐⭐⭐⭐</td><td>⭐⭐⭐</td></tr></tbody></table><p><strong>推荐使用 WebSocket 方式</strong>，除非您有特殊需求必须使用 Webhook。</p><h2 id="_2-在云湖平台创建机器人" tabindex="-1">2. 在云湖平台创建机器人 <a class="header-anchor" href="#_2-在云湖平台创建机器人" aria-label="Permalink to &quot;2. 在云湖平台创建机器人&quot;">​</a></h2><blockquote><p><strong>教程以 云湖Windows版客户端 演示</strong></p></blockquote><p>访问 <a href="https://www.yhchat.com/" target="_blank" rel="noreferrer">云湖官网</a> ，下载并安装对应的客户端。</p><p>注册并登录账号后，进入设置页面，创建一个新的机器人。</p><p>根据页面提示，完成机器人的 头像、名称、简介 的配置。</p><p><img src="'+i+'" alt="云湖后台"></p><h2 id="_3-获取机器人-token" tabindex="-1">3. 获取机器人 Token <a class="header-anchor" href="#_3-获取机器人-token" aria-label="Permalink to &quot;3. 获取机器人 Token&quot;">​</a></h2><p>打开 <strong>机器人控制台</strong>，复制机器人的 Token：</p><ul><li><strong>机器人 Token</strong>：这是与云湖 API 通信的密钥。</li></ul><p><img src="'+l+'" alt="获取机器人Token"></p><h2 id="_3-1-配置订阅事件" tabindex="-1">3.1 配置订阅事件 <a class="header-anchor" href="#_3-1-配置订阅事件" aria-label="Permalink to &quot;3.1 配置订阅事件&quot;">​</a></h2><p>打开 <strong>机器人控制台</strong>，配置机器人接收的事件：</p><blockquote><p>可以全部都勾选上</p></blockquote><p><img src="'+s+'" alt="alt"></p><h2 id="_4-配置-koishi-适配器" tabindex="-1">4. 配置 Koishi 适配器 <a class="header-anchor" href="#_4-配置-koishi-适配器" aria-label="Permalink to &quot;4. 配置 Koishi 适配器&quot;">​</a></h2><p>在 Koishi 的插件市场中找到并安装 <code>adapter-yunhupro</code> 适配器，然后进入配置页面。</p><h3 id="基础配置" tabindex="-1">基础配置 <a class="header-anchor" href="#基础配置" aria-label="Permalink to &quot;基础配置&quot;">​</a></h3><ol><li><strong>Token</strong>：填入上一步获取的机器人 Token</li><li><strong>订阅方式</strong>：选择连接方式 <ul><li><code>websocket</code>（默认，推荐）：无需公网 IP</li><li><code>webhook</code>：需要公网 IP</li></ul></li></ol><h3 id="websocket-方式配置-推荐" tabindex="-1">WebSocket 方式配置（推荐） <a class="header-anchor" href="#websocket-方式配置-推荐" aria-label="Permalink to &quot;WebSocket 方式配置（推荐）&quot;">​</a></h3><p>选择 <code>websocket</code> 订阅方式后：</p><ul><li><strong>云湖 websocket 地址</strong>：默认为 <code>wss://ws.jwzhd.com/subscribe</code>，通常无需修改</li></ul><p>配置完成后，保存配置即可。</p><p>适配器会自动连接到云湖平台并开始接收消息。</p><p><img src="'+n+'" alt="WebSocket配置示例"></p><h3 id="webhook-方式配置-可选" tabindex="-1">Webhook 方式配置（可选） <a class="header-anchor" href="#webhook-方式配置-可选" aria-label="Permalink to &quot;Webhook 方式配置（可选）&quot;">​</a></h3><p>选择 <code>webhook</code> 订阅方式后：</p><ul><li><strong>本机监听路径</strong>：默认为 <code>/yunhu</code>，您可以自定义</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p><strong>关于监听路径的重要说明</strong></p><p>如果您需要运行多个云湖机器人实例，请为每个实例配置<strong>不同的监听路径</strong>。</p><p>例如：</p><ul><li>机器人 A：<code>/yunhu1</code></li><li>机器人 B：<code>/yunhu2</code></li></ul><p>使用相同的路径会导致消息混乱！</p></div><h2 id="_5-websocket-方式-测试连接" tabindex="-1">5. WebSocket 方式：测试连接 <a class="header-anchor" href="#_5-websocket-方式-测试连接" aria-label="Permalink to &quot;5. WebSocket 方式：测试连接&quot;">​</a></h2><p>如果您选择的是 <strong>WebSocket 方式</strong>，配置完成后：</p><ol><li>保存配置，适配器会自动启动</li><li>查看 Koishi 控制台日志，确认是否显示 <code>WebSocket连接已建立</code></li><li>直接向机器人发送消息测试即可</li></ol><p><strong>无需进行后续的 Webhook 配置步骤</strong>，跳转到第 7 步进行测试。</p><h2 id="_6-webhook-方式-配置订阅地址" tabindex="-1">6. Webhook 方式：配置订阅地址 <a class="header-anchor" href="#_6-webhook-方式-配置订阅地址" aria-label="Permalink to &quot;6. Webhook 方式：配置订阅地址&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p><strong>仅适用于 Webhook 方式</strong></p><p>如果您使用的是 WebSocket 方式，请跳过此步骤。</p></div><h3 id="_6-1-确认订阅地址" tabindex="-1">6.1 确认订阅地址 <a class="header-anchor" href="#_6-1-确认订阅地址" aria-label="Permalink to &quot;6.1 确认订阅地址&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>注意：此步骤务必使用<strong>公网地址</strong>访问！</p></div><ol><li><strong>确认订阅地址</strong>：将您的 Koishi 公网访问地址与配置的 <code>path</code> 组合成完整的 Webhook URL。 <ul><li>例如，如果您的公网域名是 <code>https://your.domain.com</code>，并且 <code>path</code> 配置为 <code>/yunhu</code>，那么完整的订阅地址就是 <code>https://your.domain.com/yunhu</code>。</li></ul></li><li><strong>打开浏览器访问订阅地址</strong>： <ul><li>如果你可以访问看到 <code>适配器已成功启动</code> 页面，则说明配置成功！</li></ul></li></ol><p><img src="'+h+'" alt="适配器已成功启动"></p><h3 id="_6-2-在云湖后台配置-webhook" tabindex="-1">6.2 在云湖后台配置 Webhook <a class="header-anchor" href="#_6-2-在云湖后台配置-webhook" aria-label="Permalink to &quot;6.2 在云湖后台配置 Webhook&quot;">​</a></h3><p>回到云湖平台的机器人后台，进行以下配置：</p><ol><li><p><strong>配置订阅地址</strong>：填入您的完整订阅地址，例如 <code>https://your.domain.com/yunhu</code>。</p></li><li><p><strong>订阅事件</strong>：根据您的需求，勾选需要接收的事件类型。</p><ul><li>为了确保机器人能正常响应消息，<strong>「消息事件」</strong> 是必须订阅的。</li></ul></li></ol><p><img src="'+d+'" alt="配置订阅地址和事件"></p><h2 id="_7-测试连接" tabindex="-1">7. 测试连接 <a class="header-anchor" href="#_7-测试连接" aria-label="Permalink to &quot;7. 测试连接&quot;">​</a></h2><p>完成以上所有配置后，您可以对机器人进行一次简单的测试，以验证连接是否成功。</p><ul><li><strong>私聊</strong> 您的机器人，发送任意消息，例如 <code>status</code>。</li><li>如果您的 Koishi 机器人做出了回应，说明连接已经成功建立。</li></ul><hr><p>如果机器人没有响应，请检查以下几点：</p><h3 id="websocket-方式排查" tabindex="-1">WebSocket 方式排查 <a class="header-anchor" href="#websocket-方式排查" aria-label="Permalink to &quot;WebSocket 方式排查&quot;">​</a></h3><ul><li>Koishi 服务是否正常运行？</li><li>检查 Koishi 的控制台日志，确认 WebSocket 是否成功连接</li><li>Token 是否正确？</li><li>网络是否能访问 <code>wss://ws.jwzhd.com/subscribe</code>？</li></ul><h3 id="webhook-方式排查" tabindex="-1">Webhook 方式排查 <a class="header-anchor" href="#webhook-方式排查" aria-label="Permalink to &quot;Webhook 方式排查&quot;">​</a></h3><ul><li>Koishi 服务是否正常运行？</li><li>公网地址和 Webhook 路径是否正确？</li><li>云湖后台的事件订阅是否已开启？</li><li>检查 Koishi 的控制台日志，确认是否有来自云湖的请求或任何错误信息。</li></ul><h2 id="多机器人配置" tabindex="-1">多机器人配置 <a class="header-anchor" href="#多机器人配置" aria-label="Permalink to &quot;多机器人配置&quot;">​</a></h2><p>如果您需要运行多个云湖机器人，请使用 Koishi 的<strong>多开插件功能</strong>：</p><ol><li>在插件列表中找到 <code>adapter-yunhupro</code></li><li>点击「添加实例」按钮</li><li>为每个实例配置不同的 Token</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p><strong>WebSocket 方式</strong>：每个实例独立连接，无需额外配置</p><p><strong>Webhook 方式</strong>：每个实例必须配置不同的监听路径</p></div>',69)])])}const f=e(c,[["render",p]]);export{q as __pageData,f as default};
